INSERT INTO public.projects VALUES (1, 'Skill de deduplicación de registros de propiedades', NULL, 'Evitar que nuestro buscador muestre propiedades repetidas.', 'Implementar un sistema de deduplicación que analice los registros de propiedades provenientes de Property Finder y Bayut, identificando duplicados mediante un algoritmo de coincidencia basado en características clave como ubicación y tamaño.', '["Número de duplicados eliminados", "Precisión del algoritmo de deduplicación"]', 'Completed', '2026-03-03 21:35:25.614601+00', '2026-03-07 19:08:26.86275+00', '[]', 'Data', 'General', '[]', '[]', '[]', 0, 'TBD', '[]');
INSERT INTO public.projects VALUES (8, 'Integración Nano Banana Pro — Generación de Imágenes IA', NULL, 'Las imágenes actuales de propiedades dependen 100% de lo que provee el scraper (PropertyFinder/Bayut), sin mejora visual ni generación propia. Esto limita la calidad visual de la plataforma.', 'Integrar Nano Banana Pro como servicio de generación y mejora de imágenes para fichas de propiedades, banners y assets de marketing en la web de Emiralia.', '["Imágenes generadas por IA en al menos el 80% de fichas de propiedades", "Mejora del CTR en fichas con imágenes mejoradas vs originales", "Tiempo de generación < 10s por imagen"]', 'In Progress', '2026-03-05 11:29:44.808672+00', '2026-03-06 16:27:06.676067+00', '[]', 'Design', 'AI Images', '["Dependencia total de imágenes de terceros (scrapers)", "Calidad visual inconsistente entre propiedades", "Sin capacidad de generar banners o assets propios automáticamente"]', '["API key de Nano Banana Pro", "Storage para imágenes generadas", "Prompt engineering para propiedades inmobiliarias"]', '["Coste por llamada a la API puede escalar con volumen", "Calidad de generación puede no ser consistente para todas las tipologías", "Latencia de la API podría afectar UX si se genera on-the-fly"]', 0, '3-4 semanas', '["Generación de tours virtuales con IA", "Personalización de estilos de imagen según preferencias del comprador", "Integración con más modelos de generación (DALL-E, Midjourney API)"]');
INSERT INTO public.projects VALUES (30, '💰 Finance Agent — Registro Inteligente de Gastos e Ingresos vía Telegram', NULL, 'Emiralia no tiene trazabilidad financiera ni forma ágil de registrar movimientos desde móvil. Los gastos, facturas e ingresos se gestionan de forma manual y dispersa, sin visibilidad centralizada.', 'Finance Agent integrado con Telegram que permite subir facturas (foto, PDF o texto), extrae datos vía OCR, los almacena en una base de datos financiera propia y los visualiza en un dashboard con tabla editable y gráficos por categoría y mes.', '["100% de facturas del equipo registradas en el sistema (vs 0% actual)", "Tiempo de registro de un gasto ≤ 60 segundos desde Telegram", "Dashboard activo con al menos 30 días de histórico al cierre de Fase 1", "Tasa de éxito OCR ≥ 70% en facturas digitales estándar", "Coste mensual de infraestructura OCR ≤ $50/mes"]', 'Planning', '2026-03-08 19:17:15.786104+00', '2026-03-08 19:17:15.786104+00', '[{"type": "text", "content": "## Visión Estratégica\n\nEste proyecto resuelve uno de los puntos ciegos más críticos de Emiralia: **la invisibilidad financiera**. Sin trazabilidad de gastos, es imposible optimizar el presupuesto, detectar costes recurrentes innecesarios o reportar con credibilidad el estado del negocio.\n\nEl Finance Agent convierte Telegram —herramienta ya en uso diario por el equipo— en el punto de entrada financiero. La fricción de registrar un gasto baja de minutos a segundos: foto del ticket → OCR → confirmación → guardado. El dashboard cierra el loop con visibilidad en tiempo real.\n\nEl MVP es intencionalmente estrecho: gastos, facturas e ingresos manuales del equipo. Nada de integraciones bancarias ni tracking de propiedades en esta fase. Primero la infraestructura, luego la inteligencia."}, {"type": "callout", "title": "🎯 Core Value", "content": "El Finance Agent elimina el punto ciego financiero de Emiralia: convierte cualquier factura o gasto en un registro estructurado en menos de 60 segundos desde el móvil, con visibilidad completa en un dashboard propio. Es la base de trazabilidad que habilitará decisiones de presupuesto informadas."}, {"type": "metric_grid", "items": [{"label": "Tiempo de registro", "value": "≤ 60s"}, {"label": "Vías de entrada", "value": "3 (foto, PDF, texto)"}, {"label": "Coste OCR estimado", "value": "$0-50/mes"}, {"label": "Timeline MVP", "value": "5 semanas"}, {"label": "Budget estimado", "value": "$180"}, {"label": "Tasa OCR objetivo", "value": "≥ 70%"}]}]', 'ops', 'finance', '["Sin trazabilidad financiera: no existe registro centralizado de gastos, facturas ni ingresos del equipo, lo que impide saber cuánto se gasta en APIs, herramientas o proveedores.", "Fricción en el registro: actualmente subir una factura requiere acceso manual a hojas de cálculo o correo, sin opción móvil, lo que resulta en registros tardíos o inexistentes.", "Sin visibilidad por categoría/mes: no hay dashboard que muestre tendencias de gasto, lo que dificulta detectar costes zombies o sobrepasar presupuestos por área."]', '["Bot de Telegram con comandos /factura, /gasto, /ingreso que acepten foto, PDF o texto plano como input.", "Integración con servicio OCR (Google Document AI, Tesseract o Mindee) para extraer automáticamente fecha, importe, proveedor y categoría de facturas.", "Base de datos financiera propia (PostgreSQL) con esquema: id, tipo (gasto/ingreso/factura), fecha, importe, proveedor, categoría, descripción, archivo_url, creado_por.", "Fallback de edición manual vía Telegram cuando OCR falla o extrae datos incompletos (bot solicita confirmación o corrección campo a campo).", "Dashboard web dedicado con tabla tipo spreadsheet editable (filtro por fecha, categoría, tipo) y gráficos de barras/línea por mes y por categoría.", "Almacenamiento de archivos adjuntos (fotos y PDFs) en storage persistente (S3 o equivalente).", "Acceso al bot restringido a usuarios autorizados del equipo Emiralia."]', '["Riesgo: PDFs escaneados con baja calidad pueden resultar en OCR con extracción incompleta o errónea. Mitigación: flujo de confirmación obligatoria vía Telegram antes de guardar; fallback a ingreso manual campo a campo.", "Riesgo: Coste OCR externo recurrente (~$20-50/mes según volumen). Mitigación: evaluar Tesseract local como primera opción gratuita; escalar a API externa solo si el volumen lo justifica.", "Riesgo: Adopción baja si el flujo de Telegram tiene demasiados pasos. Mitigación: diseñar el flujo happy path en máximo 3 interacciones para el caso más común (foto de ticket).", "Riesgo: Scope creep hacia tracking de ingresos por propiedad/cliente, que requiere integración con datos de listings. Mitigación: excluir explícitamente en MVP; dejar como Fase 2 documentada."]', 180, '5 semanas', '["Tracking de ingresos por propiedad/cliente: vincular cada ingreso con un listing específico de la DB de propiedades para calcular ROI por activo.", "Alertas automáticas por Telegram cuando el gasto mensual supera umbrales definidos por categoría.", "Exportación a PDF/Excel del resumen financiero mensual con formato de informe ejecutivo.", "Integración con el EOD Generator para incluir resumen de movimientos financieros del día en el reporte diario.", "Reconciliación automática con extractos bancarios (CSV upload) para detectar gastos no registrados."]');
INSERT INTO public.projects VALUES (31, '💬 Agent Chat Console — Interfaz 1:1 por Agente con Ejecución Real de Tools', NULL, 'Interactuar con un agente requiere acceso técnico a Claude Code, bloqueando al equipo no-técnico de operar directamente con los agentes del sistema.', 'Consola de chat 1:1 por agente integrada en el Dashboard: el usuario abre un chat, el contexto del agente se inyecta automáticamente, puede instruirlo en lenguaje natural y el agente ejecuta tools reales con un log de acciones visible en tiempo real.', '["Al menos 3 miembros no-técnicos del equipo pueden operar con un agente sin abrir Claude Code", "El agente ejecuta correctamente al menos 5 tools existentes desde el chat con log visible", "Latencia de respuesta del chat < 5 segundos para el 90% de las interacciones"]', 'Planning', '2026-03-08 19:21:55.199225+00', '2026-03-08 19:21:55.199225+00', '[{"type": "text", "content": "## Por qué este proyecto es un multiplicador de fuerza\n\nHoy los agentes de Emiralia son herramientas de alto valor atrapadas detrás de una barrera técnica. Solo quien conoce Claude Code y la arquitectura del sistema puede instruirlos. Esto crea una dependencia crítica en el equipo técnico para tareas que deberían ser operativas.\n\nEste proyecto rompe esa barrera. Al crear una consola de chat 1:1 por agente dentro del Dashboard, cualquier miembro del equipo puede instruir al Data Agent para ejecutar una deduplicación, pedirle al Content Agent que genere fichas, o consultar al PM Agent el estado del backlog — en lenguaje natural, desde el navegador.\n\nEl MVP es deliberadamente austero: chat funcional, tools reales, log de acciones. Sin editor visual, sin permisos complejos. El valor está en desbloquearlo rápido."}, {"type": "callout", "title": "🎯 Core Value", "content": "Pasar de ''solo el técnico puede hablar con los agentes'' a ''cualquiera del equipo puede operar con los agentes desde el Dashboard'' en 4 semanas. Eso multiplica la capacidad operativa del sistema sin añadir headcount técnico."}, {"type": "metric_grid", "items": [{"label": "Agentes activados en MVP", "value": "6"}, {"label": "Tools ejecutables en chat", "value": "~15"}, {"label": "Tiempo estimado de entrega", "value": "4 semanas"}, {"label": "Presupuesto estimado", "value": "$200"}, {"label": "Reducción de dependencia técnica", "value": "~70%"}]}]', 'dev', 'dashboard', '["Bloqueo operativo: cualquier interacción con un agente requiere abrir Claude Code y conocer la arquitectura técnica del sistema", "Oportunidad perdida: el equipo no-técnico no puede aprovechar los agentes existentes para tareas operativas del día a día"]', '["WebSocket o long-polling para respuestas en tiempo real desde el backend hacia el Dashboard", "API de ejecución de tools: cada agente debe poder invocar sus tools registradas (tools/) desde el backend Node.js", "Inyección automática de contexto del sistema al abrir el chat (WAT Memory + estado del agente desde DB)", "Historial de conversación persistente por agente almacenado en DB", "Log de acciones en tiempo real: cada tool ejecutada debe emitir un evento visible en la UI", "Auth por agente: solo usuarios autorizados pueden abrir el chat de un agente específico"]', '["Riesgo 1: El backend actual puede no tener una capa de ejecución de tools desacoplada del CLI, lo que requiere refactoring antes de exponer tools vía API — Mitigación: auditar tools/ en la primera fase e identificar cuáles son invocables sin dependencias de terminal", "Riesgo 2: Las respuestas del LLM pueden ser lentas o fallar en producción si no hay manejo de errores robusto en el streaming — Mitigación: implementar timeout, retry y fallback visible en UI desde el día 1", "Riesgo 3: Sin permisos granulares en MVP, cualquier usuario con acceso al Dashboard puede instruir a cualquier agente — Mitigación: auth por agente basada en roles simples (admin/viewer) como primer control"]', 200, '4 semanas', '["Editor visual para crear y modificar tools/skills desde el Dashboard sin tocar código", "Permisos granulares avanzados: qué tools puede ejecutar cada rol de usuario por agente", "Historial compartido entre agentes: que el PM Agent pueda ver el historial de conversaciones con otros agentes para coordinación"]');
INSERT INTO public.projects VALUES (32, '🔍 SEO & AEO Agent — Posicionamiento Orgánico e IA para Emiralia en Español', NULL, 'Emiralia no captura tráfico orgánico en español ni aparece como fuente citada en motores de IA (ChatGPT, Perplexity, Gemini), perdiendo un canal clave de captación para el mercado hispanohablante de compradores e inversores inmobiliarios en EAU.', 'Agente SEO & AEO autónomo que optimiza fichas de propiedades existentes (metas, H1s, schema markup inmobiliario), genera contenido de blog en español con keywords de alto valor, y estructura el contenido con FAQs y datos verificables para ser citado por IAs. Se apoya en la DB de propiedades real de Emiralia para ganar autoridad como fuente de datos.', '["Tráfico orgánico en español: +500 visitas/mes desde Google en 90 días post-lanzamiento", "Keywords posicionadas: Top 20 en Google para al menos 10 keywords target en español (ej: ''apartamentos Dubai inversores'') en 60 días", "Citaciones en AI Search: Emiralia aparece como fuente en al menos 3 respuestas de Perplexity/ChatGPT sobre propiedades en EAU en 90 días", "Fichas optimizadas: 100% de propiedades en DB con meta title, meta description y schema markup correctos al cierre de Fase 2", "Artículos de blog publicados: Mínimo 8 posts en español con keyword targeting en los primeros 30 días de operación del agente", "Tasa de aprobación de contenido: >80% de los artículos generados aprobados por Content Agent sin revisión mayor"]', 'Planning', '2026-03-08 19:29:42.367402+00', '2026-03-08 19:29:42.367402+00', '[{"type": "text", "content": "## Visión Estratégica\n\nEl **SEO & AEO Agent** es la palanca de crecimiento orgánico de Emiralia. Mientras los competidores internacionales dominan el inglés, existe una ventana táctica clara: **nadie domina el SEO inmobiliario en español para EAU**.\n\nEste agente opera en dos frentes simultáneos:\n\n1. **SEO tradicional (Google)**: Optimización de fichas + blog automático con keywords de alta intención de compra en español.\n2. **AEO/GEO (AI Search)**: Estructurar el contenido de Emiralia para ser la fuente que citan ChatGPT, Perplexity y Gemini cuando alguien pregunta sobre invertir en Dubai.\n\nLa ventaja competitiva real es que Emiralia tiene algo que los blogs genéricos no tienen: **datos reales de 300+ propiedades** que dan credibilidad factual al contenido, un ingrediente esencial para E-E-A-T y para que las IAs confíen en la fuente."}, {"type": "callout", "title": "🎯 Core Value", "content": "Emiralia pasa de ser invisible en buscadores a convertirse en la referencia en español sobre propiedades en EAU, captando tráfico orgánico gratuito y siendo citada por IAs como fuente autoritativa. Cada ficha y artículo generado es un activo permanente que trabaja 24/7 sin coste adicional."}, {"type": "metric_grid", "items": [{"label": "Keywords objetivo (Fase 1)", "value": "50 KWs"}, {"label": "Blog posts en 30 días", "value": "8 artículos"}, {"label": "Fichas optimizadas", "value": "300+"}, {"label": "Tráfico orgánico objetivo", "value": "+500/mes"}, {"label": "Presupuesto estimado", "value": "$320/mes"}, {"label": "Timeline MVP", "value": "5 semanas"}]}, {"type": "text", "content": "## Arquitectura del Agente\n\n### Skills Core del SEO Agent\n\n**1. `keyword-research.js`**\nConecta con SEMrush/Ahrefs API para extraer keywords en español relacionadas con propiedades EAU. Filtra por volumen, intención de compra y dificultad. Output: lista priorizada de keywords con métricas.\n\n**2. `on-page-optimizer.js`**\nAnaliza fichas existentes en DB y genera meta titles, meta descriptions y H1s optimizados. Respeta longitudes máximas y incluye keyword principal de forma natural.\n\n**3. `schema-generator.js`**\nGenera JSON-LD para `RealEstateListing`, `FAQPage` y `Article`. Se alimenta de datos reales de la DB (precio, zona, m², ROI estimado).\n\n**4. `blog-writer.js`**\nGenera artículos de blog en español con estructura AEO: introducción con keyword, secciones con H2/H3, FAQs al final, datos reales de propiedades embebidos. Output: borrador para revisión de Content Agent.\n\n**5. `aeo-faq-builder.js`**\nExtrae las preguntas más frecuentes sobre propiedades EAU (desde PAA de Google + foros en español) y genera respuestas concisas y verificables, óptimas para ser citadas por IAs.\n\n**6. `rank-tracker.js`**\nMonitorea posiciones en Google vía Google Search Console API y rastreador manual de menciones en Perplexity/ChatGPT. Genera reporte semanal automático.\n\n**7. `content-calendar.js`**\nPlanifica el calendario editorial del blog basándose en estacionalidad, trending topics y gaps de keywords detectados."}]', 'content', 'seo', '["Tráfico orgánico cero: Emiralia no aparece en búsquedas en español como ''apartamentos en Dubai para inversores'' o ''pisos en Abu Dhabi'', perdiendo miles de búsquedas mensuales de alto intento de compra.", "Invisibilidad en AI Search: ChatGPT, Perplexity y Gemini no citan a Emiralia al responder preguntas sobre propiedades en EAU, cediendo autoridad y leads a competidores internacionales.", "Contenido desaprovechado: La DB de propiedades contiene 300+ registros con datos reales que podrían generar contenido de alta credibilidad automáticamente, pero no se usa para SEO.", "Dependencia de tráfico pagado: Sin orgánico, cada visita tiene coste, lo que hace insostenible el crecimiento a largo plazo."]', '["SEMrush API o Ahrefs API: Para keyword research automatizado y rank tracking en Google (keywords en español sobre propiedades EAU).", "Acceso a DB de propiedades de Emiralia: Para extraer datos reales (precios, zonas, ROI) que alimenten el contenido con autoridad factual.", "Schema Markup Inmobiliario (JSON-LD): Implementación de RealEstateListing, FAQPage y Article schema para AEO/GEO.", "Content Agent: Colaboración para redacción y revisión de calidad de posts de blog y fichas optimizadas.", "Dev Agent: Para inyectar metas tags, H1s y schema markup en las fichas del frontend de Emiralia.", "Data Agent: Para proporcionar feeds de datos actualizados de propiedades que el SEO Agent consuma.", "Rank Tracking en AI Search: Herramienta o método para monitorear si Emiralia aparece como fuente en respuestas de ChatGPT, Perplexity y Gemini.", "CMS o endpoint de blog: Donde el agente pueda publicar o proponer artículos generados automáticamente."]', '["Riesgo 1: Calidad del contenido generado sin revisión humana — El blog automático puede producir texto genérico o con errores que dañe la credibilidad SEO. Mitigación: Implementar flujo de revisión por Content Agent antes de publicar; en MVP, el agente propone y un humano aprueba.", "Riesgo 2: Dependencia de APIs de pago (SEMrush/Ahrefs) — Coste mensual recurrente que puede ser elevado si se usan calls intensivamente. Mitigación: Usar plan básico + caché de resultados de keyword research; revisar alternativas como Google Search Console API (gratuita) para rank tracking inicial.", "Riesgo 3: Cambios de algoritmo de Google o de políticas de IAs — Las reglas de AEO/GEO son nuevas y cambian rápido. Mitigación: Basar el contenido en principios de E-E-A-T (experiencia, expertise, autoridad, confianza) que son estables a largo plazo.", "Riesgo 4: Sin Dev Agent disponible, las optimizaciones on-page no se pueden desplegar. Mitigación: Priorizar contenido de blog en Fase 1 (sin dependencia de Dev) y dejar on-page para Fase 2.", "Riesgo 5: Datos de propiedades desactualizados o incompletos en DB — El contenido basado en datos erróneos daña la autoridad. Mitigación: El agente debe verificar freshness con Data Agent antes de usar cualquier dato en contenido público."]', 320, '5 semanas', '["Link Building Automatizado: Identificar oportunidades de guest posts en medios latinoamericanos de inversión inmobiliaria y automatizar outreach.", "SEO Técnico Profundo: Auditoría de Core Web Vitals, crawl budget, canonicals y sitemap dinámico integrado con la DB de propiedades.", "Dashboard de Rankings: Panel visual en tiempo real con posiciones en Google y presencia en respuestas de IAs para el equipo.", "Contenido Multiidioma Expandido: Extender optimización a portugués (mercado brasileño) y francés, reutilizando la arquitectura del agente.", "Agente de Backlinks: Monitoreo automático del perfil de enlaces entrantes y alertas de link rot o tóxicos.", "Integración con Telegram Bot: Recibir alertas semanales de ranking changes, nuevas keywords de oportunidad y menciones en IAs directamente en Telegram."]');
INSERT INTO public.projects VALUES (33, '📢 SEM Agent — Gestión Autónoma de Campañas Google Ads Sincronizada con Inventario', NULL, 'Sin automatización, el gasto en Google Ads no escala con el inventario real: se generan clics desperdiciados a listados inexistentes o sin stock, quemando presupuesto y distorsionando el ROAS.', 'Un agente SEM autónomo que sincroniza el inventario de propiedades en DB con las campañas activas de Google Ads, generando ad copy en español, ajustando pujas según disponibilidad real y enviando reportes ROAS semanales vía Telegram.', '["ROAS > 3x en las primeras 4 semanas de operación autónoma", "0 anuncios activos para propiedades sin stock tras sincronización", "Reducción del CPC promedio ≥ 15% vs. gestión manual baseline", "Reporte semanal ROAS entregado vía Telegram sin intervención humana", "Tiempo de sincronización inventario → campañas < 1 hora desde detección de cambio"]', 'Planning', '2026-03-08 19:33:07.802702+00', '2026-03-08 19:33:07.802702+00', '[{"type": "text", "content": "## Por qué este agente es prioritario\n\nEn paid media, cada AED desperdiciado en un clic a una propiedad inexistente no es solo un coste directo: deteriora el Quality Score de Google Ads, encareciendo todos los clics futuros. El SEM Agent no es solo automatización — es **defensa del presupuesto** y **amplificador del inventario real**.\n\nLa sincronización con `query_properties.js` es el núcleo diferencial: convierte el buscador de Emiralia en una fuente de verdad que alimenta directamente las campañas, eliminando la fricción entre el equipo de datos y el equipo de marketing."}, {"type": "callout", "title": "🎯 Core Value", "content": "Cada propiedad activa en DB genera automáticamente un anuncio optimizado en Google Ads. Cada propiedad retirada pausa su anuncio en menos de 1 hora. Cero intervención manual. ROAS visible cada semana en Telegram."}, {"type": "metric_grid", "items": [{"label": "Duración MVP", "value": "4 semanas"}, {"label": "ROAS objetivo", "value": "> 3x"}, {"label": "Canales MVP", "value": "Google Ads"}, {"label": "Presupuesto estimado", "value": "$420"}, {"label": "Tiempo sync inventario", "value": "< 1h"}, {"label": "Reporting", "value": "Semanal vía Telegram"}]}]', 'marketing', 'paid media', '["Clics desperdiciados: Anuncios activos para propiedades que ya no están en el inventario generan gasto sin conversión posible.", "Escalado manual: Cada cambio en el stock requiere intervención humana para actualizar campañas, creando un cuello de botella operativo.", "Sin visibilidad ROAS: No hay reporting automático que conecte el gasto en ads con leads reales generados por propiedad."]', '["Google Ads API: Acceso OAuth2 con permisos de lectura/escritura sobre campañas, grupos de anuncios y anuncios.", "Google Analytics API (GA4): Para conectar clics de ads con sesiones y conversiones en el sitio de Emiralia.", "Google Keyword Planner API: Para investigación de keywords con intención de compra inmobiliaria en español.", "tools/db/query_properties.js: Acceso al inventario real de propiedades para sincronización activa de campañas.", "tools/telegram/bot.js: Para entrega de reportes semanales de ROAS y alertas de anomalías de gasto.", "Cuenta Google Ads activa con presupuesto configurado y acceso MCC (My Client Center) si aplica.", "Credenciales de servicio (Service Account o OAuth2) para acceso programático a todas las APIs de Google."]', '["Riesgo 1 — Quota y costes de Google Ads API: La API tiene límites de operaciones diarias; campañas con mucho volumen pueden saturar quotas. Mitigación: Implementar cola de operaciones con rate limiting y caché de estado de campañas para minimizar llamadas innecesarias.", "Riesgo 2 — Modificaciones destructivas en campañas activas: Un bug en la sincronización podría pausar campañas o alterar pujas de forma inesperada. Mitigación: Modo dry-run obligatorio en las primeras 2 semanas; toda acción destructiva requiere confirmación explícita vía log antes de ejecutarse.", "Riesgo 3 — Desincronización DB ↔ Ads: Si query_properties.js devuelve datos stale, los anuncios pueden activarse para propiedades sin stock. Mitigación: Validar timestamp de last_scrape_at antes de cada ciclo de sincronización; alertar si el dato tiene más de 24h.", "Riesgo 4 — Calidad del ad copy generado en español: Copy mal adaptado al mercado EAU puede reducir CTR y Quality Score. Mitigación: Integrar Translation Agent para revisión de terminología inmobiliaria EAU; A/B testing de variantes desde la fase 2."]', 420, '4 semanas', '["Meta Ads Integration: Expandir el agente a campañas de Facebook/Instagram Ads con el mismo motor de sincronización de inventario.", "Bidding automático avanzado: Implementar estrategias de Smart Bidding personalizadas basadas en historial de conversiones por tipo de propiedad (villa, apartamento, etc.).", "Lead scoring por campaña: Conectar leads generados vía ads con el CRM para calcular CPL real por segmento y optimizar presupuesto dinámicamente.", "Dashboard de ROAS en tiempo real: Integrar con el frontend de Emiralia un panel visible para el equipo, más allá del reporte Telegram.", "Remarketing dinámico: Crear audiencias automáticas basadas en propiedades vistas y lanzar campañas de retargeting sincronizadas con el inventario."]');
INSERT INTO public.projects VALUES (34, '📱 Media Buyer Agent — Optimización Asistida de Campañas Meta & TikTok vía Telegram', NULL, 'La gestión manual de campañas en Meta y TikTok es reactiva y lenta: las oportunidades de optimización se pierden por falta de monitoreo continuo, y los ajustes llegan tarde cuando el CPL ya se disparó o el budget ya se agotó.', 'Un agente asistido que corre en background, extrae métricas en tiempo real de Meta Ads API y TikTok Ads API, detecta anomalías contra umbrales configurables, genera propuestas de acción concretas (pausar adset, ajustar puja, redirigir budget) y las envía vía Telegram para aprobación con un tap. Cada decisión —aprobada o rechazada— queda logueada para retroalimentar el agente con el tiempo.', '["Tiempo de detección de anomalías < 60 minutos desde que ocurren", "Tasa de aprobación de propuestas > 60% (indica que las sugerencias son relevantes)", "Reducción del CPL promedio ≥ 15% en las primeras 4 semanas post-lanzamiento", "Cobertura de monitoreo: 100% de campañas activas revisadas cada hora sin intervención manual", "Log de decisiones con ≥ 30 entradas en el primer mes (señal de uso activo)"]', 'Planning', '2026-03-08 19:37:45.427557+00', '2026-03-08 19:37:45.427557+00', '[{"type": "text", "content": "## Visión Estratégica\n\nEl **Media Buyer Agent** transforma la gestión de paid media de reactiva a proactiva. En lugar de revisar dashboards manualmente, el agente trabaja 24/7 como un analista junior que nunca duerme: extrae métricas, las compara contra umbrales, y cuando detecta una oportunidad o un problema, lo escala con una propuesta concreta lista para aprobar con un tap.\n\nEl modelo asistido es clave: mantiene al humano en el loop de decisiones importantes mientras elimina la carga de monitoreo continuo. Cada aprobación o rechazo alimenta el log que, en iteraciones futuras, permitirá calibrar el agente hacia mayor autonomía con confianza.\n\n### Arquitectura de 4 capas\n1. **Pull Layer**: Cron job horario que extrae métricas de Meta API y TikTok API\n2. **Detection Layer**: Motor de reglas contra umbrales configurables por campaña\n3. **Proposal Layer**: Generador de acciones concretas con contexto y justificación\n4. **Approval Layer**: Telegram bot con InlineKeyboard + log de decisiones"}, {"type": "callout", "title": "🎯 Core Value", "content": "El agente no reemplaza al media buyer — amplifica su capacidad de reacción. Un humano solo puede revisar campañas 2-3 veces al día; el agente las revisa cada hora y solo interrumpe cuando hay algo accionable. Resultado: más optimizaciones, menos tiempo operativo, mejor ROAS."}, {"type": "metric_grid", "items": [{"label": "Plataformas cubiertas", "value": "Meta + TikTok"}, {"label": "Frecuencia de monitoreo", "value": "Cada hora"}, {"label": "Tiempo de reacción estimado", "value": "< 60 min"}, {"label": "Reducción CPL objetivo", "value": "≥ 15%"}, {"label": "Presupuesto estimado", "value": "$180 USD"}, {"label": "Timeline", "value": "4 semanas"}]}]', 'marketing', 'paid_media', '["Monitoreo reactivo: los problemas (CPL alto, CTR bajo, budget agotado) se detectan horas después de ocurrir, cuando el daño ya está hecho.", "Oportunidades perdidas: escalados de adsets ganadores y pausas de perdedores se hacen manualmente y con retraso, reduciendo el ROAS potencial.", "Carga operativa: revisar métricas de 2 plataformas a diario consume tiempo del equipo que podría invertirse en estrategia y creatividades."]', '["Meta Marketing API: acceso con token de larga duración, permisos ads_read + ads_management sobre la cuenta de negocio.", "TikTok Ads API: credenciales de developer app con acceso a reporting y campaign management.", "Telegram Bot API: bot con webhook o polling, soporte de InlineKeyboardMarkup para botones Aprobar/Rechazar.", "Base de datos de configuración: tabla de umbrales por campaña (CPL máximo, CTR mínimo, % budget consumido para alerta).", "Log de decisiones: tabla persistente con timestamp, propuesta, acción sugerida y decisión del usuario (aprobada/rechazada/ignorada).", "Scheduler: cron job cada hora para pull de métricas + trigger diario para reporte de performance consolidado."]', '["Riesgo: Rate limits de Meta API y TikTok API pueden bloquear pulls frecuentes si hay muchas campañas activas. Mitigación: implementar backoff exponencial y cachear métricas por ventana de 15 min en lugar de pull en tiempo real.", "Riesgo: Falsos positivos en alertas (anomalías que no son reales) generan fatiga de aprobación y el usuario empieza a ignorar los mensajes. Mitigación: calibrar umbrales conservadoramente en la fase 1 y ajustar con el log de decisiones.", "Riesgo: Cambios en la estructura de respuesta de las APIs (versioning) pueden romper el parser de métricas sin aviso. Mitigación: versionar explícitamente las llamadas a API y añadir test de sanidad en cada run.", "Riesgo: El token de Meta expira cada 60 días si no se renueva. Mitigación: implementar alerta proactiva 7 días antes de expiración vía Telegram."]', 180, '4 semanas', '["Modo autónomo con límites: permitir que el agente ejecute acciones de bajo impacto (ej: pausar adsets con 0 conversiones y >50 clics) sin aprobación, solo con notificación.", "Análisis de creatividades: integrar con el Design Agent para correlacionar CTR con el asset creativo y sugerir qué creatividades escalar o retirar.", "Forecasting de budget: proyectar cuándo se agotará el budget diario/mensual basándose en el ritmo de gasto actual.", "Expansión a Google Ads: añadir un tercer canal con la misma arquitectura de alertas y aprobación.", "Dashboard de performance: vista consolidada de métricas cross-platform en la interfaz de Emiralia."]');
INSERT INTO public.projects VALUES (35, '🎬 Social Media Agent — Contenido IG & TikTok con Fernando & Yolanda', NULL, 'Emiralia carece de presencia orgánica consistente en redes sociales hispanohablantes. La producción manual de contenido para IG y TikTok es lenta, inconsistente y no escala. Sin un flujo estructurado, se pierden oportunidades de captación orgánica en el mercado hispano de EAU.', 'Agente de Social Media que guioniza contenido adaptado a la personalidad de Fernando y Yolanda (presentadores reales), genera calendarios editoriales semanales y estructura el flujo de producción con CapCut AI para edición. La IA actúa como el cerebro creativo y organizador; los humanos ejecutan la grabación y presentación.', '["Cadencia de publicación: mínimo 3 piezas/semana publicadas durante el primer mes", "Tiempo de guionización: de idea a guion listo en menos de 30 minutos por pieza", "Consistencia de voz: 0 revisiones mayores de estilo en los guiones tras validación inicial de personas", "Engagement rate IG/TikTok: +15% en las primeras 8 semanas vs baseline actual", "Buffer editorial: calendario con mínimo 2 semanas de contenido guionizado por adelantado en todo momento"]', 'Planning', '2026-03-08 19:43:54.761239+00', '2026-03-08 19:43:54.761239+00', '[{"type": "text", "content": "## Visión Estratégica\n\nEste agente convierte a Emiralia en el referente de contenido inmobiliario EAU en español. La combinación de **presentadores humanos reales** (autenticidad) + **guionización IA** (escala) + **edición CapCut AI** (velocidad) es el stack ganador para TikTok e IG en 2025.\n\nEl diferencial no es solo el contenido, es la **consistencia de marca** que se logra cuando la IA conoce profundamente a Fernando y Yolanda y puede generar voz auténtica a escala."}, {"type": "callout", "title": "🎯 Core Value", "content": "El activo más valioso de este proyecto no es la tecnología: son las personas de Fernando y Yolanda. Una vez definidas correctamente, la IA puede producir guiones ilimitados que suenan genuinamente a ellos. Eso es imposible de replicar por la competencia."}, {"type": "callout", "title": "⚠️ Decisiones de Arquitectura", "content": "**Descartado**: avatares IA, HeyGen, lip-sync. El enfoque es humano-primero con IA como soporte creativo y organizacional. Esto reduce la complejidad técnica y el riesgo de ''uncanny valley'' que aleja audiencias."}, {"type": "metric_grid", "items": [{"label": "Presentadores", "value": "2 (Fernando & Yolanda)"}, {"label": "Pilares de Contenido", "value": "3"}, {"label": "Cadencia Objetivo", "value": "3-5 piezas/sem"}, {"label": "Herramienta de Edición", "value": "CapCut AI"}, {"label": "Plataformas", "value": "IG + TikTok"}, {"label": "Timeline MVP", "value": "3 semanas"}]}]', 'marketing', 'social_media', '["Producción de contenido: actualmente no existe un flujo estructurado de guionización → grabación → edición → publicación, lo que genera cuellos de botella y ausencia de calendario editorial", "Consistencia de voz: sin una definición formal de las ''personas'' de Fernando y Yolanda, cada pieza de contenido suena diferente, dificultando la construcción de audiencia fiel", "Escalabilidad: sin IA guionizando y organizando, el equipo no puede mantener la cadencia necesaria (3-5 piezas/semana) para que el algoritmo de TikTok e IG favorezca la cuenta", "Oportunidad perdida: el nicho hispano interesado en real estate de EAU es altamente específico y casi sin competencia en redes sociales en español"]', '["Definición de Personas: documento estructurado con el estilo, tono, catchphrases, temas de expertise y personalidad de Fernando y Yolanda para alimentar los prompts de guionización", "Motor de guionización: prompts especializados por pilar de contenido (Lifestyle emiratí, Real Estate, Tours de propiedades) que generen guiones adaptados al presentador asignado", "Calendario editorial: generación semanal/mensual de temas, formatos y asignación de presentador por pieza, alineado con fechas relevantes del mercado inmobiliario EAU", "Flujo CapCut AI: estructura de briefing de edición compatible con las funciones AI de CapCut (captions automáticos, cortes por ritmo, música sugerida)", "Integración con inventario Emiralia: acceso a la DB de propiedades para guionizar tours y vídeos de propiedades específicas con datos reales", "Canal de distribución: conexión con Telegram o panel interno para que el equipo reciba guiones y calendario listos para ejecutar"]', '["Riesgo 1: Las personas de Fernando y Yolanda no están definidas formalmente → los guiones sonarán genéricos y perderán autenticidad. Mitigación: Sprint 0 dedicado exclusivamente a construir los documentos de persona antes de generar un solo guion.", "Riesgo 2: Dependencia de disponibilidad de grabación humana → si Fernando o Yolanda no tienen tiempo, el calendario se bloquea. Mitigación: generar guiones con 2 semanas de antelación y mantener un buffer de contenido evergreen ya guionizado.", "Riesgo 3: CapCut AI cambia sus features o limitaciones → el flujo de edición queda desactualizado. Mitigación: documentar el flujo como ''recomendación de edición'' en lenguaje agnóstico a la herramienta, no como automatización hard-coded.", "Riesgo 4: El contenido de Real Estate requiere datos precisos de propiedades → errores en precios o disponibilidad pueden dañar la credibilidad. Mitigación: integrar validación con DB de Emiralia antes de publicar cualquier guion con datos de propiedades."]', 150, '3 semanas', '["Análisis de rendimiento: agente que lea métricas de IG/TikTok y ajuste los temas del calendario según engagement real", "Banco de hooks: librería de aperturas de vídeo de alta conversión, testeadas y organizadas por pilar temático", "Automatización de publicación: conexión directa con APIs de IG/TikTok para scheduling automático desde el calendario generado", "Subtitulado multiidioma: generación automática de subtítulos en inglés/árabe para ampliar el alcance a audiencias no hispanohablantes en EAU", "Tour virtual con IA: en fase avanzada, explorar integración de imágenes de propiedades con narración en voz de los presentadores (sin lip-sync, solo voz + imágenes)"]');
INSERT INTO public.projects VALUES (36, '📧 Email Marketing Agent — Nurturing Automatizado de Leads Hispanohablantes', NULL, 'Sin un canal de nurturing estructurado, los leads hispanohablantes de Emiralia se enfrían tras el primer contacto y no convierten. No existe automatización que mantenga el interés del lead con contenido relevante sobre propiedades en EAU según su perfil e intención de compra.', 'Un Email Marketing Agent que automatiza la comunicación con leads segmentados por perfil (inversor, comprador final, curioso) y comportamiento. El agente genera campañas personalizadas en español, lanza alertas automáticas cuando entran propiedades que hacen match con el perfil del lead, ejecuta A/B testing, y retroalimenta el sistema con métricas de engagement para optimizar segmentos continuamente.', '["Open rate ≥ 30% en campañas segmentadas (benchmark sector inmobiliario: 20-25%)", "CTR ≥ 5% en emails de alerta de propiedades", "Tasa de conversión lead→consulta activa ≥ 8% tras 60 días de nurturing", "Reducción del tiempo de respuesta a lead nuevo: de manual a automático en < 5 minutos", "Al menos 2 variantes A/B testeadas por campaña con decisión automática"]', 'Planning', '2026-03-08 19:47:55.562526+00', '2026-03-08 19:47:55.562526+00', '[{"type": "text", "content": "## Por qué este agente es prioritario\n\nEl email marketing sigue siendo el canal con mayor ROI en real estate: por cada $1 invertido, genera ~$36 de retorno (DMA, 2023). Para Emiralia, con un mercado hispanohablante que confía más en comunicación personalizada que en publicidad fría, el nurturing vía email es el puente entre captación y conversión.\n\nHoy ese puente no existe. Cada lead que entra al sistema tiene una ventana de 48-72h de máximo interés — pasada esa ventana, el costo de reactivarlo es 5x mayor. Este agente cierra esa brecha de forma automatizada, escalable y en español."}, {"type": "callout", "title": "🎯 Core Value", "content": "El Email Marketing Agent convierte leads fríos en compradores activos mediante nurturing automatizado en español, alertas de propiedades en tiempo real y optimización continua basada en datos de comportamiento — sin intervención humana en el día a día."}, {"type": "metric_grid", "items": [{"label": "Timeline", "value": "4 semanas"}, {"label": "Budget estimado", "value": "$350"}, {"label": "Open rate objetivo", "value": "≥ 30%"}, {"label": "CTR objetivo", "value": "≥ 5%"}, {"label": "Agentes involucrados", "value": "3 (PM, Content, Dev)"}, {"label": "Riesgo principal", "value": "Lista de leads vacía"}]}]', 'marketing', 'email_marketing', '["Leads fríos: sin nurturing, los leads que entran al funnel se enfrían en 48-72h y no convierten — tasa de conversión lead→cliente estimada por debajo del 2%", "Comunicación manual: hoy no existe un flujo automatizado de emails en español adaptado al perfil del lead, lo que significa oportunidades perdidas cada vez que entra una propiedad relevante al inventario", "Sin loop de datos: no hay visibilidad de qué mensajes, segmentos o propiedades generan más interés real (clicks, respuestas, conversiones)"]', '["API de plataforma de envío: Brevo (Sendinblue) o Mailchimp — necesaria para envíos transaccionales, campañas y métricas", "Acceso a DB de propiedades: integración con la base de datos existente para lanzar alertas automáticas cuando entran propiedades que hacen match con perfil del lead", "Integración con Content Agent: para generación de copy de emails en español con tono inmobiliario de alta calidad", "Sistema de segmentación: lógica de clasificación de leads por perfil (inversor / comprador final / curioso) y por comportamiento (clicks, aperturas, propiedades vistas)", "Almacenamiento de lista de leads: definir si existe base de leads activa o si hay que construir el flujo de captación (riesgo pendiente)", "Motor de A/B testing: soporte para variantes de subject lines y contenido con decisión automática basada en open rate"]', '["Riesgo crítico: base de leads vacía o inexistente — si no hay lista activa, el agente no tiene a quién enviar. Mitigación: auditar lista existente en semana 1; si no existe, priorizar flujo de captación como prerequisito antes de activar campañas", "Riesgo de deliverability: dominio de envío sin warmup puede caer en spam. Mitigación: configurar SPF/DKIM/DMARC desde día 1 y hacer warmup progresivo antes del primer envío masivo", "Riesgo de segmentación vacía: si los perfiles de leads no tienen datos suficientes, la segmentación será superficial. Mitigación: implementar segmentación por comportamiento como fallback cuando no hay datos de perfil declarados", "Riesgo de dependencia con Content Agent: delays en generación de copy pueden bloquear campañas. Mitigación: crear biblioteca de templates base reutilizables para los primeros 30 días"]', 350, '4 semanas', '["Integración con CRM: sincronizar estado del lead (frío/tibio/caliente) con un CRM para que ventas sepa cuándo contactar", "Secuencias de drip avanzadas: flujos de nurturing de 30-60-90 días con ramificación según comportamiento del lead", "Lead scoring automático: asignar puntuación al lead en función de aperturas, clicks y propiedades vistas para priorizar seguimiento comercial", "Personalización dinámica: insertar propiedades recomendadas en el cuerpo del email en tiempo real según perfil y historial", "Integración con Telegram bot: notificar al equipo cuando un lead supera un umbral de engagement (lead caliente listo para contacto directo)"]');
INSERT INTO public.projects VALUES (37, '📊 Analytics Agent — Inteligencia Unificada de Marketing y Producto para Emiralia', NULL, 'Las decisiones de marketing y producto se toman sin datos centralizados ni alertas proactivas, generando puntos ciegos operativos que impiden reaccionar a tiempo ante caídas de tráfico, anomalías de conversión o cambios en el comportamiento de búsqueda.', 'Crear un Analytics Agent que unifique datos de GA4 y la DB interna de propiedades en un sistema de inteligencia operativa con dos lentes: Marketing (CTR, costo por lead, fuentes de tráfico) y Producto (búsquedas frecuentes, propiedades más vistas, filtros usados). El agente entrega un resumen diario automático vía Telegram y detecta anomalías de forma proactiva.', '["Reporte diario entregado vía Telegram antes de las 09:00 AM GST con 100% de uptime en las primeras 2 semanas post-lanzamiento.", "Detección de al menos 1 anomalía real accionable en las primeras 4 semanas (validada por el equipo).", "Reducción a 0 del tiempo manual dedicado a consolidar KPIs de GA4 y DB (actualmente estimado en 2-3 horas semanales).", "Cobertura de KPIs: mínimo 5 métricas de Marketing y 5 de Producto incluidas en el reporte MVP."]', 'Planning', '2026-03-08 19:52:18.779466+00', '2026-03-08 19:52:18.779466+00', '[{"type": "text", "content": "## Visión Estratégica\n\nEl **Analytics Agent** es la capa de inteligencia operativa que Emiralia necesita para pasar de decisiones reactivas a decisiones informadas. Hoy, los datos de comportamiento de usuarios (GA4) y los datos de inventario (DB interna) viven en silos. Este agente los une, los interpreta y los entrega de forma proactiva cada mañana.\n\nEl diseño en **dos lentes** (Marketing + Producto) es clave: no se trata solo de saber cuánto tráfico llega, sino de entender qué buscan los usuarios y si el inventario disponible satisface esa demanda. Esta correlación es el verdadero diferencial competitivo.\n\nEl MVP prioriza velocidad de valor: GA4 + DB interna son las fuentes con menor fricción de integración. Meta Ads y Google Ads API quedan para Fase 2, cuando ya tengamos la arquitectura validada."}, {"type": "callout", "title": "🎯 Core Value", "content": "Este proyecto convierte datos dispersos en inteligencia accionable diaria. El primer reporte automático que llegue por Telegram antes de las 9 AM será el momento en que Emiralia deje de operar a ciegas. Es infraestructura de decisión, no solo un dashboard."}, {"type": "metric_grid", "items": [{"label": "Ahorro estimado", "value": "2-3h/semana"}, {"label": "Time to first insight", "value": "Semana 2"}, {"label": "Fuentes MVP", "value": "GA4 + DB"}, {"label": "KPIs cubiertos", "value": "10 mínimo"}, {"label": "Presupuesto estimado", "value": "$120 USD"}, {"label": "Timeline", "value": "3 semanas"}]}]', 'ops', 'analytics', '["Decisiones a ciegas: no existe un reporte consolidado de KPIs de marketing y producto; cada análisis requiere trabajo manual que tarda horas.", "Anomalías no detectadas: caídas de tráfico, picos de rebote o propiedades sin impresiones pasan desapercibidas hasta que ya causaron daño.", "Datos fragmentados: GA4, DB interna y futuras fuentes publicitarias viven en silos sin conexión ni correlación automática."]', '["GA4 Data API v1 con autenticación OAuth 2.0 o Service Account para acceso a métricas de sesiones, conversiones y fuentes de tráfico.", "Acceso de lectura a la DB interna de propiedades para consultar vistas, búsquedas frecuentes y filtros usados.", "Bot de Telegram activo (ya disponible en tools/telegram/bot.js) para entrega de reportes diarios.", "Nueva tool query_analytics.js para agregación de métricas cross-source (GA4 + DB).", "Nueva tool ga4-connector.js para autenticación y extracción de datos desde GA4 Data API.", "Nueva tool report-generator.js para construir el resumen diario estructurado con ambos lentes.", "Nueva tool anomaly-detector.js con lógica de umbrales dinámicos (desviación estándar sobre ventana de 7 días).", "Scheduler o cron job para ejecución automática diaria del agente (ej: 08:00 AM GST)."]', '["Riesgo principal — Autenticación OAuth de GA4: el flujo OAuth requiere intervención manual inicial y tokens de refresco que pueden expirar. Mitigación: usar Service Account en lugar de OAuth user-based para autenticación headless sin intervención humana.", "Riesgo de calidad de datos — DB interna: los 300 registros actuales y la presencia de 6,679 duplicados marcados pueden distorsionar métricas de producto. Mitigación: filtrar solo propiedades con status activo y usar los tiers de deduplicación ya calculados por data-agent.", "Riesgo de alertas ruidosas: umbrales estáticos generan falsos positivos y fatiga de notificaciones. Mitigación: implementar umbrales dinámicos basados en media móvil de 7 días desde el primer sprint.", "Riesgo de scope creep — APIs de pago: presión para integrar Meta Ads o Google Ads API antes de validar el MVP. Mitigación: documentar explícitamente en el backlog que estas integraciones son Fase 2 y requieren aprobación de PM."]', 120, '3 semanas', '["Integración con Meta Ads API y Google Ads API para cerrar el ciclo de atribución completo (impresión → clic → lead → cierre).", "Dashboard visual interactivo (web o Notion embed) con histórico de KPIs y gráficos de tendencia para los lentes de Marketing y Producto.", "Motor de recomendaciones: cruzar propiedades más buscadas vs menos visibles en SEO para generar sugerencias automáticas de contenido al Content Agent.", "Segmentación geográfica de búsquedas: detectar qué zonas del EAU generan más interés entre usuarios hispanohablantes para informar estrategia de inventario.", "Integración con Finance Agent (Proyecto #30) para correlacionar gasto publicitario con calidad de leads y ROI real."]');
INSERT INTO public.projects VALUES (38, '📈 CRO Agent — Optimización de Conversión e Instrumentación para Emiralia', NULL, 'Emiralia no tiene visibilidad del comportamiento de usuarios en la web (sin GA4 ni Hotjar), lo que imposibilita identificar fricciones, priorizar mejoras con datos reales y optimizar la conversión de visitas a leads cualificados.', 'Crear un CRO Agent que arranque con la instrumentación completa (GA4 + Hotjar), construya un dashboard de métricas clave y genere hipótesis CRO priorizadas por impacto. En v2, el agente gestionará tests A/B de forma autónoma y rastreará resultados.', '["GA4 + Hotjar operativos y recogiendo datos en menos de 5 días desde inicio del proyecto", "Dashboard con métricas clave (tasa de conversión, páginas de mayor abandono, fuentes de tráfico) live en semana 2", "Mínimo 5 hipótesis CRO priorizadas por impacto/esfuerzo entregadas al final de la semana 3", "0 errores en tracking de eventos de lead (formulario de contacto, clicks en WhatsApp, solicitudes de info)"]', 'Planning', '2026-03-08 20:00:05.196051+00', '2026-03-08 20:00:05.196051+00', '[{"type": "text", "content": "## Por qué el CRO Agent empieza por la instrumentación\n\nNo se puede optimizar lo que no se mide. Emiralia tiene tráfico activo, campañas en marcha y un inventario creciente — pero opera con visibilidad cero del comportamiento de sus usuarios. Cada visita que no convierte es un dato perdido para siempre.\n\nEl CRO Agent resuelve esto en tres pasos secuenciales:\n1. **Instrumentación** (semana 1): GA4 + Hotjar + GTM. La base de datos de comportamiento empieza a crecer desde el día 1.\n2. **Visibilidad** (semana 2): Dashboard en Looker Studio con las métricas que importan: dónde entran los usuarios, dónde se van, y cuántos convierten.\n3. **Inteligencia** (semana 3): Con los primeros datos reales, el agente genera hipótesis CRO priorizadas — las primeras decisiones de optimización basadas en evidencia, no en intuición."}, {"type": "callout", "title": "🎯 Core Value", "content": "Sin este proyecto, todos los demás agentes de marketing (SEM, Social, Email) están optimizando a ciegas. El CRO Agent es la capa de inteligencia que cierra el loop: sabe qué tráfico convierte, qué fricción lo impide, y qué cambiar para mejorar el ROI de toda la inversión en adquisición."}, {"type": "metric_grid", "items": [{"label": "Tiempo al primer dato", "value": "< 5 días"}, {"label": "Costo herramientas MVP", "value": "~$0 (Hotjar free + Looker Studio free)"}, {"label": "Hipótesis CRO entregadas", "value": "5+ en semana 3"}, {"label": "Dependencias críticas", "value": "1 (Dev Agent para GTM)"}, {"label": "Timeline total", "value": "3 semanas"}, {"label": "Tests A/B en MVP", "value": "No (v2)"}]}]', 'marketing', 'cro', '["Ceguera total de datos: Sin GA4 ni Hotjar, no hay forma de saber qué páginas tienen mayor abandono, dónde se pierden los leads ni qué elementos generan fricción en el funnel.", "Optimización a ciegas: Las decisiones de mejora UX/UI se toman sin evidencia, desperdiciando esfuerzo del Dev Agent y Design Agent en cambios que pueden no tener impacto real.", "Oportunidad perdida: Con el inventario activo y campañas en marcha (SEM, Social, Email), cada semana sin datos de conversión es dinero invertido en tráfico que no se puede optimizar."]', '["Acceso al frontend de Emiralia para inyección de scripts GA4 y Hotjar (requiere colaboración con Dev Agent)", "Cuenta Google Analytics 4 con propiedad configurada para emiralia.com", "Licencia Hotjar (plan básico gratuito suficiente para MVP: hasta 35 sesiones/día)", "Google Tag Manager instalado en el frontend para gestión de tags sin deploys frecuentes", "Acceso a Google Search Console para correlacionar tráfico orgánico con conversión", "Dashboard tool: Looker Studio (gratuito) conectado a GA4 para visualización de métricas"]', '["Riesgo 1: Dependencia del Dev Agent para instalar GTM/GA4/Hotjar — si hay bloqueo en el frontend, el proyecto entero se paraliza. Mitigación: Hacer de la instalación de GTM la tarea #1 del sprint, con prioridad máxima y tiempo acotado (máx 2 días).", "Riesgo 2: Volumen de tráfico insuficiente para obtener datos estadísticamente significativos en 3 semanas. Mitigación: Usar Hotjar para insights cualitativos (heatmaps, recordings) que no requieren volumen alto, y fijar expectativas: el dashboard v1 será orientativo, no concluyente.", "Riesgo 3: Configuración incorrecta de eventos GA4 (leads no trackeados correctamente). Mitigación: QA de eventos con GA4 DebugView antes de dar por completada la fase 1.", "Riesgo 4: Scope creep hacia tests A/B en el MVP. Mitigación: Los tests A/B están explícitamente excluidos del alcance y documentados como v2."]', 150, '3 semanas', '["v2 — Gestión autónoma de tests A/B: El CRO Agent propone variantes, el Dev Agent las implementa con feature flags, y el agente monitorea resultados y declara ganador automáticamente.", "v2 — Integración con Analytics Agent (Proyecto #37): Cruzar datos de conversión CRO con datos de campañas de marketing para atribución completa del funnel.", "v3 — Personalización dinámica: Mostrar contenido diferente según segmento de usuario (inversor vs comprador de primera vivienda) basado en comportamiento detectado por GA4.", "v3 — Alertas automáticas vía Telegram: El CRO Agent notifica caídas de conversión o anomalías de tráfico en tiempo real al equipo."]');
INSERT INTO public.projects VALUES (39, '🖥️ Agent Workspaces — Vistas Personalizadas por Agente y Tipo de Artefacto', NULL, 'La interfaz actual del Agent Chat Console es genérica y no refleja los outputs radicalmente distintos de cada agente (blogs, dashboards, assets financieros), lo que obliga a revisar artefactos fuera de contexto y ralentiza la aprobación y publicación.', 'Construir una capa de workspaces modulares dentro del Agent Chat Console (proyecto 31): una tabla compartida `artifacts` como fuente de verdad, y una vista personalizada por agente que filtra por `agent_id + type` y expone acciones contextuales específicas (aprobar, rechazar, editar, publicar) según el tipo de artefacto.', '["Tabla `artifacts` operativa con los 8 tipos soportados y datos reales de al menos 2 agentes en semana 2", "2 workspaces piloto (Content + Finance) funcionales con acciones de aprobar/rechazar/editar en semana 3", "Los 8 workspaces desplegados con acciones contextuales completas al cierre de la semana 4", "Tiempo de revisión y aprobación de artefactos reducido vs. proceso manual actual (baseline a medir en semana 1)"]', 'Planning', '2026-03-08 20:19:50.365797+00', '2026-03-08 20:19:50.365797+00', '[{"type": "text", "content": "## Visión Estratégica\n\nEmiralia opera con 8 agentes especializados que generan artefactos radicalmente distintos: un blog post no se revisa igual que un ad creative ni que un finance entry. Sin embargo, hoy no existe infraestructura para gestionar estos outputs de forma estructurada.\n\nEste proyecto establece **la capa de gestión de artefactos de Emiralia**: una arquitectura de datos compartida (`artifacts`) y workspaces modulares que dan a cada agente su interfaz natural de trabajo. Es infraestructura de plataforma que desbloquea la operación real de todos los agentes de contenido, marketing y finanzas."}, {"type": "callout", "title": "🎯 Core Value", "content": "Sin workspaces personalizados, los agentes generan outputs que nadie puede revisar ni aprobar de forma eficiente. Este proyecto convierte a Emiralia en un sistema operativo real: cada agente tiene su panel de control, cada artefacto tiene un ciclo de vida claro, y el equipo tiene visibilidad total del flujo de contenido y aprobaciones."}, {"type": "metric_grid", "items": [{"label": "Agentes con workspace propio", "value": "8"}, {"label": "Tipos de artefacto soportados", "value": "8"}, {"label": "Workspaces piloto en semana 3", "value": "2"}, {"label": "Timeline total", "value": "4 semanas"}, {"label": "Presupuesto estimado", "value": "$300"}, {"label": "Dependencia principal", "value": "Proyecto 31 (Agent Chat Console)"}]}]', 'dev', 'platform', '["Revisión fuera de contexto: los agentes generan outputs muy distintos (blog posts, spreadsheets, ad creatives) pero hoy no existe una interfaz para revisarlos, aprobarlos o actuar sobre ellos de forma estructurada.", "Fricción operativa: sin acciones contextuales por tipo de artefacto, cada aprobación requiere intervención manual fuera del sistema, aumentando el tiempo de ciclo de contenido y campañas.", "Deuda de arquitectura: sin una tabla `artifacts` centralizada, cada agente guardaría sus outputs en estructuras dispares, imposibilitando métricas cruzadas y auditoría."]', '["DB: Crear tabla `artifacts` con schema `{id, agent_id, type, content, status, metadata, created_at, updated_at}`", "Backend: API REST o RPC para CRUD de artefactos con filtros por `agent_id` y `type`", "Frontend: Sistema de routing modular dentro del Agent Chat Console que cargue el workspace correcto según el agente activo", "Vistas específicas: 8 módulos de workspace (Content, SEO, Social Media, Email, Finance, Analytics, CRO, Media Buyer) con acciones contextuales por tipo", "Acciones mínimas por artefacto: aprobar, rechazar, editar (inline o modal), y marcar como publicado", "Tipos de artefacto soportados en MVP: `blog_post`, `email_template`, `social_asset`, `finance_entry`, `report`, `keyword`, `ad_creative`, `ab_test`"]', '["Riesgo 1: Scope creep por querer diseñar las 8 vistas simultáneamente — ralentiza entrega y fragmenta el foco. Mitigación: Fase 1 solo arquitectura + 2 workspaces piloto (Content + Finance, los más distintos entre sí), el resto en fases posteriores.", "Riesgo 2: Dependencia del proyecto 31 (Agent Chat Console) — si ese contenedor no está listo, los workspaces no tienen dónde vivir. Mitigación: Asumir que el routing y shell del proyecto 31 están disponibles; si no, construir un shell temporal standalone.", "Riesgo 3: Diseño visual no definido puede generar retrabajo. Mitigación: Usar componentes UI existentes del sistema (tablas, cards, modales) sin diseño custom en MVP; iterar visual en fase 2.", "Riesgo 4: La lógica de ''push a web'' para contenido aprobado está fuera de alcance pero puede generar expectativas. Mitigación: El status `published` se guarda en DB pero la integración con el sitio web se pospone explícitamente a futuras mejoras."]', 300, '4 semanas', '["Push a web automatizado: cuando un artefacto tipo `blog_post` o `social_asset` se aprueba, publicación directa vía API al CMS o plataforma social correspondiente.", "Diseño visual diferenciado: UI/UX específica por tipo de workspace con identidad propia (ej: vista Kanban para Social Media, tabla financiera para Finance Agent).", "Historial y versioning de artefactos: comparar versiones de un mismo artefacto antes de aprobar, con diff visual.", "Métricas cruzadas de artefactos: dashboard que muestra tasa de aprobación, tiempo promedio de revisión y volumen de outputs por agente.", "Notificaciones Telegram: alertas automáticas cuando un artefacto pasa a status `pending_review` para agilizar el ciclo de aprobación."]');
