INSERT INTO public.projects VALUES (40, '⚖️ Legal Agent — Asesoría Inmobiliaria en Español sobre Marco Legal EAU', NULL, 'Los compradores hispanohablantes generan fricción en el funnel de compra por desconocimiento del marco legal de EAU (RERA, freehold zones, visas de inversor). Actualmente el equipo resuelve estas dudas manualmente, lo que escala mal y retrasa la conversión.', 'Un Legal Agent que responda preguntas frecuentes sobre la ley inmobiliaria de Emiratos en español, cubriendo la fase educativa del lead (RERA, freehold zones, proceso de compra, visas de inversor). Incluye disclaimer legal automático y fecha de última actualización en cada respuesta para mitigar liability.', '["Reducción de consultas legales manuales al equipo en ≥60% en el primer mes post-lanzamiento.", "Tasa de satisfacción del lead con las respuestas ≥4/5 (encuesta post-interacción).", "≥80% de preguntas respondidas sin escalado humano.", "Tiempo medio de respuesta a consulta legal: <10 segundos."]', 'Planning', '2026-03-09 12:33:57.441978+00', '2026-03-09 12:33:57.441978+00', '[{"type": "text", "content": "## Contexto Estratégico\n\nEl desconocimiento del marco legal de EAU es uno de los mayores inhibidores de conversión para el comprador hispanohablante. Preguntas como *¿puedo comprar como extranjero?*, *¿qué es una freehold zone?* o *¿cómo funciona la Golden Visa?* aparecen repetidamente en el funnel y consumen tiempo del equipo sin generar valor escalable.\n\nEl **Legal Agent** resuelve esto con una base de conocimiento estructurada sobre RERA, DIFC y normativa freehold, servida en español con disclaimers automáticos. El MVP se focaliza en la fase educativa del lead — el momento donde el conocimiento legal convierte curiosidad en intención de compra."}, {"type": "callout", "title": "⚖️ Core Value", "content": "Cada lead hispanohablante que no entiende el marco legal de EAU es un lead que no convierte. El Legal Agent es el primer agente de Emiralia con impacto directo en la educación del comprador — y por tanto, en la tasa de conversión del funnel."}, {"type": "metric_grid", "items": [{"label": "Ahorro estimado", "value": "15h/mes"}, {"label": "Cobertura MVP", "value": "Fase pre-compra"}, {"label": "Idioma de respuesta", "value": "Español"}, {"label": "Timeline MVP", "value": "3 semanas"}, {"label": "Presupuesto estimado", "value": "$350"}, {"label": "Fuentes base", "value": "RERA, DIFC, Freehold"}]}]', 'content', 'legal-intelligence', '["Fricción manual: El equipo responde dudas legales individualmente, consumiendo ~10-15h/mes sin escalar.", "Oportunidad perdida: Leads que no entienden el marco legal de EAU abandonan el funnel antes de calificarse como compradores reales.", "Riesgo de desinformación: Sin una fuente estructurada y actualizada, las respuestas manuales pueden ser inconsistentes o desactualizadas."]', '["Base de conocimiento legal estructurada: RERA, DIFC, normativa freehold, zonas permitidas para extranjeros, proceso SPA.", "LLM con RAG: Sistema de recuperación sobre documentos legales oficiales para respuestas precisas y citadas.", "Disclaimer legal automático: Cada respuesta incluye aviso de que no es asesoría legal vinculante + fecha de última actualización.", "Interfaz de consulta: Integración con el flujo existente (web o Telegram) para que el lead pueda hacer preguntas en español.", "Exploración del repo cc-wf-studio: Evaluar si su sistema de orquestación es compatible como framework base del agente."]', '["Riesgo 1: Liability legal — Respuestas incorrectas sobre regulación pueden generar reclamaciones. Mitigación: Disclaimer obligatorio en cada respuesta + revisión trimestral de la base de conocimiento con fuentes oficiales.", "Riesgo 2: Desactualización normativa — RERA actualiza regulaciones periódicamente. Mitigación: Versionar la base de conocimiento con fecha y crear un proceso de revisión mensual asignado al Content Agent.", "Riesgo 3: Scope creep post-venta — Extender el agente a contratos, transferencias y visas de residencia antes de validar el MVP educativo. Mitigación: Alcance explícitamente limitado a fase pre-compra en esta fase.", "Riesgo 4: Compatibilidad cc-wf-studio — El repo puede no ser compatible con la arquitectura actual de Emiralia. Mitigación: Sprint de exploración técnica (2 días) antes de comprometer el framework."]', 350, '3 semanas', '["Fase 2: Cobertura post-venta — Contratos SPA, transferencias en DLD, visas de residencia Golden Visa.", "Fase 3: Actualización automática — Research Agent monitorea cambios en RERA y alerta cuando la base de conocimiento requiere revisión.", "Fase 4: Personalización por perfil — Respuestas adaptadas según el tipo de comprador (inversor, primera vivienda, visa, etc.).", "Integración con CRO Agent — Medir qué preguntas legales tienen mayor correlación con conversión para priorizar contenido."]');
INSERT INTO public.phases VALUES (1, 1, 1, 'Análisis y Diseño', 'Definir criterios y algoritmos de deduplicación.', '2026-03-03 21:35:25.614601+00');
INSERT INTO public.phases VALUES (2, 1, 2, 'Desarrollo e Implementación', 'Desarrollar e integrar el sistema de deduplicación.', '2026-03-03 21:35:25.614601+00');
INSERT INTO public.phases VALUES (3, 1, 3, 'Pruebas y Validación', 'Asegurar la efectividad del sistema de deduplicación.', '2026-03-03 21:35:25.614601+00');
INSERT INTO public.phases VALUES (9, 8, 1, 'Investigación y Setup', 'Evaluar la API de Nano Banana Pro y definir los casos de uso para Emiralia', '2026-03-05 11:29:44.808672+00');
INSERT INTO public.phases VALUES (10, 8, 2, 'Integración técnica', 'Desarrollar el wrapper de la API y el pipeline de generación de imágenes', '2026-03-05 11:29:44.808672+00');
INSERT INTO public.phases VALUES (11, 8, 3, 'Integración en la web', 'Mostrar imágenes generadas por IA en la plataforma y optimizar para rendimiento web', '2026-03-05 11:29:44.808672+00');
INSERT INTO public.phases VALUES (15, 12, 1, 'Infraestructura de Tracking', 'Crear la tabla DB y el wrapper de tracking listo para ser importado por cualquier tool', '2026-03-06 06:19:46.111418+00');
INSERT INTO public.phases VALUES (16, 12, 2, 'Reporte de Ranking vía Telegram', 'Comando Telegram que muestra el ranking de uso de tools con frecuencia y última ejecución', '2026-03-06 06:19:46.111418+00');
INSERT INTO public.phases VALUES (17, 12, 3, 'Integración con WAT Auditor', 'El WAT Auditor detecta automáticamente tools no instrumentadas y las reporta como gap de cobertura', '2026-03-06 06:19:46.111418+00');
INSERT INTO public.phases VALUES (19, 28, 1, 'Creación del Research Agent', 'Crear el Research Agent desde cero: definir su identidad, registrarlo en DB y construir la skill de monitoreo semanal con output estructurado.', '2026-03-07 20:03:56.339734+00');
INSERT INTO public.phases VALUES (20, 28, 2, 'Integración con WAT Auditor', 'Actualizar el WAT Auditor para consumir el output del Research Agent como contexto externo en sus auditorías, cruzando el estado interno del sistema con las novedades externas.', '2026-03-07 20:03:56.339734+00');
INSERT INTO public.phases VALUES (21, 28, 3, 'Validación y Ajuste de Calidad', 'Validar que el sistema genera señal útil (no ruido), ajustar filtros según feedback del primer ciclo real, y documentar el Research Agent.', '2026-03-07 20:03:56.339734+00');
INSERT INTO public.phases VALUES (22, 29, 1, 'Instrumentación y Logging', 'Añadir capa de observabilidad al PM Agent que registre cada tool llamada, su orden y si retornó datos, sin modificar el comportamiento del agente.', '2026-03-08 07:41:05.096386+00');
INSERT INTO public.phases VALUES (23, 29, 2, 'Reporte Visual y Análisis Inicial', 'Generar reporte legible del flujo real de contexto por sesión y ejecutar primera auditoría para identificar patrones de contexto faltante.', '2026-03-08 07:41:05.096386+00');
INSERT INTO public.phases VALUES (24, 30, 1, 'Infraestructura Base — DB Financiera + Bot Telegram', 'Establecer la base de datos financiera y el bot de Telegram funcional para registro manual de gastos, facturas e ingresos vía texto, sin OCR aún.', '2026-03-08 19:17:15.786104+00');
INSERT INTO public.phases VALUES (25, 30, 2, 'OCR Intelligence — Extracción Automática de Facturas', 'Integrar OCR para extraer automáticamente datos de facturas subidas como foto o PDF, con flujo de confirmación/corrección vía Telegram.', '2026-03-08 19:17:15.786104+00');
INSERT INTO public.phases VALUES (26, 30, 3, 'Dashboard Financiero — Tabla + Gráficos', 'Crear dashboard web dedicado con tabla editable tipo spreadsheet y gráficos de gasto/ingreso por categoría y por mes.', '2026-03-08 19:17:15.786104+00');
INSERT INTO public.phases VALUES (27, 30, 4, 'Integración y Pulido — QA + Documentación', 'Pruebas end-to-end del flujo completo, corrección de bugs, documentación de uso y despliegue en producción.', '2026-03-08 19:17:15.786104+00');
INSERT INTO public.phases VALUES (28, 31, 1, 'Backend: API de Chat y Capa de Ejecución de Tools', 'Construir el backend que recibe mensajes, invoca al LLM con contexto del agente, ejecuta tools reales y devuelve respuestas + logs en tiempo real.', '2026-03-08 19:21:55.199225+00');
INSERT INTO public.phases VALUES (29, 31, 2, 'Frontend: Consola de Chat en el Dashboard', 'Construir la interfaz de chat 1:1 por agente en el Dashboard con UX clara, log de acciones visible y respuestas en tiempo real.', '2026-03-08 19:21:55.199225+00');
INSERT INTO public.phases VALUES (30, 31, 3, 'QA, Activación de Agentes y Lanzamiento Interno', 'Verificar que cada agente ejecuta sus tools correctamente desde el chat, pulir la experiencia y hacer el lanzamiento interno con el equipo no-técnico.', '2026-03-08 19:21:55.199225+00');
INSERT INTO public.phases VALUES (31, 32, 1, 'Fundación: Keyword Intelligence + Blog MVP', 'Establecer la base de conocimiento SEO del agente y lanzar los primeros 8 artículos de blog en español con targeting de keywords de alta oportunidad, sin dependencia de Dev Agent.', '2026-03-08 19:29:42.367402+00');
INSERT INTO public.phases VALUES (32, 32, 2, 'On-Page Optimization + Schema Markup', 'Optimizar las 300+ fichas de propiedades existentes con metas, H1s y schema markup inmobiliario, y desplegar structured data en el sitio para mejorar CTR en Google y elegibilidad para AI citations.', '2026-03-08 19:29:42.367402+00');
INSERT INTO public.phases VALUES (33, 32, 3, 'Automatización Continua + Rank Tracking', 'Poner el agente en modo operación continua: calendario editorial automatizado, monitoring de rankings en Google y detección de menciones en AI search, con reporte semanal vía Telegram.', '2026-03-08 19:29:42.367402+00');
INSERT INTO public.phases VALUES (34, 33, 1, 'Infraestructura y Conexiones', 'Establecer todas las conexiones API, autenticación y acceso al inventario. Al final de esta fase, el agente puede leer campañas existentes y propiedades en DB.', '2026-03-08 19:33:07.802702+00');
INSERT INTO public.phases VALUES (35, 33, 2, 'Core SEM Skills — Gestión de Campañas', 'Implementar las skills principales del agente: creación/pausa de anuncios sincronizados con stock, generación de ad copy en español y gestión de keywords.', '2026-03-08 19:33:07.802702+00');
INSERT INTO public.phases VALUES (36, 33, 3, 'Análisis, ROAS y Reporting', 'Activar el loop de optimización: el agente analiza rendimiento, ajusta pujas y entrega reportes automáticos ROAS semanales vía Telegram.', '2026-03-08 19:33:07.802702+00');
INSERT INTO public.phases VALUES (37, 33, 4, 'QA, Activación y Monitoreo', 'Validar el sistema completo en producción, desactivar el modo dry-run y establecer monitoreo continuo.', '2026-03-08 19:33:07.802702+00');
INSERT INTO public.phases VALUES (38, 34, 1, 'Infraestructura & Conexión con APIs', 'Establecer las conexiones autenticadas con Meta Ads API y TikTok Ads API, definir el schema de datos y levantar el scheduler de pull de métricas.', '2026-03-08 19:37:45.427557+00');
INSERT INTO public.phases VALUES (39, 34, 2, 'Motor de Detección y Generación de Propuestas', 'Construir el motor de reglas que detecta anomalías contra umbrales y genera propuestas de acción concretas con justificación.', '2026-03-08 19:37:45.427557+00');
INSERT INTO public.phases VALUES (40, 34, 3, 'Interfaz Telegram & Log de Decisiones', 'Construir el bot de Telegram con aprobación por tap, reporte diario automático y log persistente de decisiones.', '2026-03-08 19:37:45.427557+00');
INSERT INTO public.phases VALUES (41, 34, 4, 'Calibración, QA y Lanzamiento', 'Calibrar umbrales con datos reales, ejecutar QA end-to-end y documentar el agente para operación autónoma.', '2026-03-08 19:37:45.427557+00');
INSERT INTO public.phases VALUES (42, 35, 1, 'Sprint 0 — Fundamentos: Personas & Arquitectura de Contenido', 'Definir las personas de Fernando y Yolanda y la arquitectura de contenido antes de generar un solo guion. Sin esto, todo lo siguiente es ruido.', '2026-03-08 19:43:54.761239+00');
INSERT INTO public.phases VALUES (43, 35, 2, 'MVP — Motor de Guionización & Calendario Editorial', 'Construir el sistema que genera guiones listos-para-grabar y un calendario editorial semanal automatizado.', '2026-03-08 19:43:54.761239+00');
INSERT INTO public.phases VALUES (44, 35, 3, 'Flujo de Producción — Briefing CapCut & Distribución', 'Completar el flujo desde guion hasta briefing de edición listo para CapCut AI, y distribuir el calendario al equipo vía Telegram.', '2026-03-08 19:43:54.761239+00');
INSERT INTO public.phases VALUES (45, 36, 1, 'Infraestructura y Configuración Base', 'Establecer la plataforma de envío, configurar deliverability, auditar lista de leads existente y definir la arquitectura de segmentación antes de escribir una sola línea de copy.', '2026-03-08 19:47:55.562526+00');
INSERT INTO public.phases VALUES (46, 36, 2, 'Templates, Copy y Flujos Automáticos', 'Crear la biblioteca de templates de email en español, diseñar los flujos automáticos de nurturing y construir el sistema de alertas de propiedades.', '2026-03-08 19:47:55.562526+00');
INSERT INTO public.phases VALUES (47, 36, 3, 'A/B Testing y Motor de Analytics', 'Activar el loop de optimización continua: A/B testing automático de subject lines y contenido, dashboard de métricas y retroalimentación al sistema de segmentación.', '2026-03-08 19:47:55.562526+00');
INSERT INTO public.phases VALUES (48, 36, 4, 'QA, Warmup y Go Live', 'Validar todos los flujos con envíos de prueba, completar el warmup del dominio y lanzar las primeras campañas reales con monitoreo activo.', '2026-03-08 19:47:55.562526+00');
INSERT INTO public.phases VALUES (49, 37, 1, 'Infraestructura de Datos y Conectores', 'Establecer las conexiones con GA4 y la DB interna, y construir las tools base que alimentarán al agente. Al final de esta fase, el agente puede extraer y almacenar datos de ambas fuentes sin intervención manual.', '2026-03-08 19:52:18.779466+00');
INSERT INTO public.phases VALUES (50, 37, 2, 'Motor de Reportes y Detección de Anomalías', 'Construir la lógica de generación de reportes y el detector de anomalías. Al final de esta fase, el agente puede producir un reporte estructurado y detectar desviaciones significativas respecto a la media histórica.', '2026-03-08 19:52:18.779466+00');
INSERT INTO public.phases VALUES (51, 37, 3, 'Automatización, Registro y Validación', 'Activar la ejecución automática diaria del agente, registrarlo en el sistema de agentes de Emiralia y validar el funcionamiento end-to-end con datos reales durante 5 días consecutivos.', '2026-03-08 19:52:18.779466+00');
INSERT INTO public.phases VALUES (52, 38, 1, 'Instrumentación — Base de Datos de Comportamiento', 'Instalar y verificar GA4, Hotjar y Google Tag Manager en el frontend de Emiralia, asegurando que todos los eventos críticos del funnel (visitas, formularios, clicks en CTA, solicitudes de info) se trackeан correctamente.', '2026-03-08 20:00:05.196051+00');
INSERT INTO public.phases VALUES (53, 38, 2, 'Dashboard de Métricas — Visibilidad del Funnel', 'Construir un dashboard operativo en Looker Studio que muestre en tiempo real las métricas clave del funnel: tráfico, comportamiento por página, tasa de conversión y fuentes de adquisición.', '2026-03-08 20:00:05.196051+00');
INSERT INTO public.phases VALUES (54, 38, 3, 'Hipótesis CRO — Primeras Propuestas Basadas en Datos', 'Generar y priorizar las primeras hipótesis de optimización de conversión basadas en datos reales de GA4 y Hotjar, entregando un backlog CRO priorizado por impacto/esfuerzo listo para ejecutar en el siguiente sprint.', '2026-03-08 20:00:05.196051+00');
INSERT INTO public.phases VALUES (55, 39, 1, 'Arquitectura de Datos — Tabla Artifacts', 'Establecer la fuente de verdad compartida para todos los artefactos del sistema, con schema validado y API funcional.', '2026-03-08 20:19:50.365797+00');
INSERT INTO public.phases VALUES (56, 39, 2, 'Workspaces Piloto — Content Agent + Finance Agent', 'Construir los dos workspaces más distintos entre sí (texto editorial vs. datos financieros) para validar la arquitectura modular antes de escalar a los 6 restantes.', '2026-03-08 20:19:50.365797+00');
INSERT INTO public.phases VALUES (57, 39, 3, 'Workspaces Restantes — 6 Agentes', 'Escalar el patrón validado en fase 2 a los 6 agentes restantes, adaptando las acciones contextuales y layouts al tipo de artefacto de cada uno.', '2026-03-08 20:19:50.365797+00');
INSERT INTO public.phases VALUES (58, 39, 4, 'QA, Polish y Datos Reales', 'Conectar los workspaces con artefactos reales generados por los agentes, validar flujos end-to-end y pulir UX antes del lanzamiento operativo.', '2026-03-08 20:19:50.365797+00');
INSERT INTO public.phases VALUES (59, 40, 1, 'Exploración y Base de Conocimiento', 'Evaluar el repo cc-wf-studio, estructurar las fuentes legales y definir la arquitectura del agente antes de construir.', '2026-03-09 12:33:57.441978+00');
INSERT INTO public.phases VALUES (60, 40, 2, 'Construcción del MVP', 'Implementar el agente con RAG sobre la base de conocimiento, disclaimer automático y endpoint funcional para consultas en español.', '2026-03-09 12:33:57.441978+00');
